        console.log(props.rooms)
        if(props.rooms!=[]){
            console.log("props.rooms")
        props.rooms.map((i) => { return <Room room={i}/> })}
        else {
        return <h1>No availAble rooms</h1>}}
  return (
    <div>
        {showRooms()}
    <Link to={"/"}><button>Back</button> </Link>
    </div>
  )
}
